// VoiceCallToken is the resolver for the voiceCallToken field.
// Generates a LiveKit JWT for joining a voice call.
// Returns null if LiveKit is not configured. Requires room membership.
func (r *roomResolver) VoiceCallToken(ctx context.Context, obj *corev1.Room) (*core.VoiceCallToken, error) {
	user, err := requireRoomMember(ctx, r.core, core.KindOfRoom(obj), obj.Id)
	if err != nil {
		return nil, err
	}

	if !r.livekitConfig.IsConfigured() {
		return nil, nil
	}

	avatarSize := 96
	avatarURL, _ := r.core.GetUserAvatarURL(ctx, user.Id, &avatarSize, &avatarSize, "cover")
	activeCall, ok := r.core.CallState.ActiveCall(obj.Id)
	if !ok {
		return nil, fmt.Errorf("no active voice call for room %s", obj.Id)
	}
	e2eeKey, err := r.core.GetVoiceCallE2EEKey(ctx, obj.Id)
	if err != nil {
		return nil, err
	}

	roomName := core.LiveKitRoomName(r.livekitConfig.ServerID, core.LegacySpaceIDForRoomKind(core.KindOfRoom(obj)), obj.Id)
	token, err := core.GenerateVoiceCallToken(
		r.livekitConfig.APIKey,
		r.livekitConfig.APISecret,
		roomName,
		user.Id,
		user.DisplayName,
		user.Login,
		avatarURL,
		e2eeKey,
	)
	if err != nil {
		return nil, err
	}
	token.CallID = activeCall.CallID

	return token, nil
}

// CallParticipants is the resolver for the callParticipants field.
// Returns participants currently in this room's voice call.
// Returns empty list if no call is active or LiveKit is not configured. Requires room membership.
func (r *roomResolver) CallParticipants(ctx context.Context, obj *corev1.Room) ([]*model.CallParticipant, error) {
	if _, err := requireRoomMember(ctx, r.core, core.KindOfRoom(obj), obj.Id); err != nil {
		return nil, err
	}

	if !r.livekitConfig.IsConfigured() {
		return []*model.CallParticipant{}, nil
	}

	participants, err := r.core.GetCallParticipants(ctx, core.LegacySpaceIDForRoomKind(core.KindOfRoom(obj)), obj.Id)
	if err != nil {
		return nil, err
	}

	result := make([]*model.CallParticipant, 0, len(participants))
	for _, p := range participants {
		user, err := r.getUser(ctx, p.UserID)
		if err != nil {
			if errors.Is(err, core.ErrNotFound) {
				continue
			}
			return nil, err
		}
		result = append(result, &model.CallParticipant{
			User:     user,
			JoinedAt: timestamppb.New(time.Unix(p.JoinedAt, 0)),
			CallID:   p.CallID,
		})
	}
	return result, nil
}

